static void uart_init(uint32_t baudrate)
{
    /* Enable USART1 and GPIOA clocks */
    RCC_APB2ENR |= (1 << 4);   /* USART1EN */
    RCC_AHB1ENR |= (1 << 0);   /* GPIOAEN */
    delay_cycles(10);

    /* Configure PA9 (TX) and PA10 (RX) as AF7 (USART1) */
    uint32_t moder = GPIO_MODER(BOOT_GPIO_PORT_BASE);
    moder &= ~((3 << (9 * 2)) | (3 << (10 * 2)));
    moder |= (2 << (9 * 2)) | (2 << (10 * 2));  /* Alternate function */
    GPIO_MODER(BOOT_GPIO_PORT_BASE) = moder;

    /* Set AF7 for PA9, PA10 */
    volatile uint32_t *afr_high = (volatile uint32_t *)(BOOT_GPIO_PORT_BASE + 0x24);
    uint32_t afr = *afr_high;
    afr &= ~((0xF << ((9 - 8) * 4)) | (0xF << ((10 - 8) * 4)));
    afr |= (7 << ((9 - 8) * 4)) | (7 << ((10 - 8) * 4));
    *afr_high = afr;

    /* Configure USART1 */
    USART_CR1(USART1_BASE) = 0;
    /* Baudrate: assuming 16MHz HSI clock on APB2 */
    USART_BRR(USART1_BASE) = 16000000 / baudrate;
    USART_CR1(USART1_BASE) = USART_CR1_UE | USART_CR1_TE | USART_CR1_RE;
}

static void uart_send_byte(uint8_t byte)
{
    while (!(USART_SR(USART1_BASE) & USART_SR_TXE));
    USART_DR(USART1_BASE) = byte;
    while (!(USART_SR(USART1_BASE) & USART_SR_TC));
}

static void uart_send_data(const uint8_t *data, uint32_t len)
{
    for (uint32_t i = 0; i < len; i++) {
        uart_send_byte(data[i]);
    }
}

static void uart_send_string(const char *str)
{
    while (*str) {
        uart_send_byte((uint8_t)*str++);
    }
}

static bool uart_recv_byte(uint8_t *byte, uint32_t timeout)
{
    volatile uint32_t count = timeout;
    while (!(USART_SR(USART1_BASE) & USART_SR_RXNE)) {
        if (--count == 0) return false;
    }
    *byte = (uint8_t)USART_DR(USART1_BASE);
    return true;
}

static bool uart_recv_data(uint8_t *buffer, uint32_t len, uint32_t timeout)
{
    for (uint32_t i = 0; i < len; i++) {
        if (!uart_recv_byte(&buffer[i], timeout)) {
            return false;
        }
    }
    return true;
}

static bool uart_check_activity(void)
{
    uint8_t byte;
    /* Quick check for sync byte with short timeout */
    if (uart_recv_byte(&byte, 100000)) {
        if (byte == CMD_SYNC) {
            uart_send_byte(CMD_ACK);
            return true;
        }
    }
    return false;
}

