static void spi_init(void)
{
    /* Enable SPI1 and GPIOA clocks */
    RCC_APB2ENR |= (1 << 12);  /* SPI1EN */
    RCC_AHB1ENR |= (1 << 0);   /* GPIOAEN */
    delay_cycles(10);

    /* PA5=SCK, PA6=MISO, PA7=MOSI as AF5 */
    uint32_t moder = GPIO_MODER(BOOT_GPIO_PORT_BASE);
    moder &= ~((3 << (5 * 2)) | (3 << (6 * 2)) | (3 << (7 * 2)) | (3 << (SD_CS_PIN * 2)));
    moder |= (2 << (5 * 2)) | (2 << (6 * 2)) | (2 << (7 * 2)); /* AF */
    moder |= (1 << (SD_CS_PIN * 2)); /* CS as output */
    GPIO_MODER(BOOT_GPIO_PORT_BASE) = moder;

    /* Set AF5 for PA5, PA6, PA7 */
    volatile uint32_t *afr_low = (volatile uint32_t *)(BOOT_GPIO_PORT_BASE + 0x20);
    uint32_t afr = *afr_low;
    afr &= ~((0xF << (5 * 4)) | (0xF << (6 * 4)) | (0xF << (7 * 4)));
    afr |= (5 << (5 * 4)) | (5 << (6 * 4)) | (5 << (7 * 4));
    *afr_low = afr;

    /* CS high (deselect) */
    GPIO_BSRR(SD_CS_PORT_BASE) = (1 << SD_CS_PIN);

    /* Configure SPI: Master, CPOL=0, CPHA=0, slow speed initially (fPCLK/256) */
    SPI_CR1(SPI1_BASE) = SPI_CR1_MSTR | SPI_CR1_SSM | SPI_CR1_SSI | (7 << 3);
    SPI_CR1(SPI1_BASE) |= SPI_CR1_SPE;
}

static void spi_set_fast(void)
{
    SPI_CR1(SPI1_BASE) &= ~SPI_CR1_SPE;
    SPI_CR1(SPI1_BASE) = (SPI_CR1(SPI1_BASE) & ~(7 << 3)) | (1 << 3); /* fPCLK/4 */
    SPI_CR1(SPI1_BASE) |= SPI_CR1_SPE;
}

static uint8_t spi_transfer(uint8_t data)
{
    while (!(SPI_SR(SPI1_BASE) & SPI_SR_TXE));
    SPI_DR(SPI1_BASE) = data;
    while (!(SPI_SR(SPI1_BASE) & SPI_SR_RXNE));
    return (uint8_t)SPI_DR(SPI1_BASE);
}

static void sd_cs_low(void)
{
    GPIO_BSRR(SD_CS_PORT_BASE) = (1 << (SD_CS_PIN + 16));
}

static void sd_cs_high(void)
{
    GPIO_BSRR(SD_CS_PORT_BASE) = (1 << SD_CS_PIN);
    spi_transfer(0xFF); /* Extra clocks */
}

/* ============================================================
 * SD Card Functions (Minimal SPI Mode)
 * ============================================================ */

#define SD_CMD0     0   /* GO_IDLE_STATE */
#define SD_CMD1     1   /* SEND_OP_COND */
#define SD_CMD8     8   /* SEND_IF_COND */
#define SD_CMD17    17  /* READ_SINGLE_BLOCK */
#define SD_CMD55    55  /* APP_CMD */
#define SD_ACMD41   41  /* SD_SEND_OP_COND */
#define SD_CMD58    58  /* READ_OCR */

static bool sd_initialized = false;
static bool sd_is_sdhc = false;

static uint8_t sd_send_cmd(uint8_t cmd, uint32_t arg)
{
    uint8_t response;
    uint8_t crc = 0xFF;

    if (cmd == SD_CMD0) crc = 0x95;
    if (cmd == SD_CMD8) crc = 0x87;

    spi_transfer(0xFF);
    spi_transfer(0x40 | cmd);
    spi_transfer((arg >> 24) & 0xFF);
    spi_transfer((arg >> 16) & 0xFF);
    spi_transfer((arg >> 8) & 0xFF);
    spi_transfer(arg & 0xFF);
    spi_transfer(crc);

    /* Wait for response (max 8 bytes) */
    for (int i = 0; i < 10; i++) {
        response = spi_transfer(0xFF);
        if (!(response & 0x80)) break;
    }
    return response;
}

static bool sd_init(void)
{
    uint8_t response;
    uint32_t timeout;

    spi_init();

    /* Send 80+ clock pulses with CS high */
    sd_cs_high();
    for (int i = 0; i < 12; i++) {
        spi_transfer(0xFF);
    }

    /* CMD0: Reset to idle */
    sd_cs_low();
    response = sd_send_cmd(SD_CMD0, 0);
    sd_cs_high();
    if (response != 0x01) return false;

    /* CMD8: Check voltage range (SDv2) */
    sd_cs_low();
    response = sd_send_cmd(SD_CMD8, 0x1AA);
    if (response == 0x01) {
        /* SDv2 card */
        uint8_t ocr[4];
        for (int i = 0; i < 4; i++) ocr[i] = spi_transfer(0xFF);
        sd_cs_high();

        if (ocr[2] != 0x01 || ocr[3] != 0xAA) return false;

        /* ACMD41: Initialize */
        timeout = 10000;
        do {
            sd_cs_low();
            sd_send_cmd(SD_CMD55, 0);
            sd_cs_high();
            sd_cs_low();
            response = sd_send_cmd(SD_ACMD41, 0x40000000);
            sd_cs_high();
        } while (response != 0x00 && --timeout);
        if (timeout == 0) return false;

        /* CMD58: Read OCR to check SDHC */
        sd_cs_low();
        response = sd_send_cmd(SD_CMD58, 0);
        if (response == 0x00) {
            uint8_t ocr2[4];
            for (int i = 0; i < 4; i++) ocr2[i] = spi_transfer(0xFF);
            sd_is_sdhc = (ocr2[0] & 0x40) != 0;
        }
        sd_cs_high();
    } else {
        sd_cs_high();
        /* SDv1 or MMC */
        sd_is_sdhc = false;
        timeout = 10000;
        do {
            sd_cs_low();
            sd_send_cmd(SD_CMD55, 0);
            sd_cs_high();
            sd_cs_low();
            response = sd_send_cmd(SD_ACMD41, 0);
            sd_cs_high();
        } while (response != 0x00 && --timeout);

        if (timeout == 0) {
            /* Try CMD1 for MMC */
            timeout = 10000;
            do {
                sd_cs_low();
                response = sd_send_cmd(SD_CMD1, 0);
                sd_cs_high();
            } while (response != 0x00 && --timeout);
            if (timeout == 0) return false;
        }
    }

    spi_set_fast();
    sd_initialized = true;
    return true;
}

